1	/**
2	 * Stream-JSON NDJSON parser.
3	 *
4	 * Consumes Claude Code `--output-format stream-json` stdout lines and emits
5	 * typed events. Each line is parsed independently — a malformed line emits
6	 * `parse_error` and does NOT halt the parser.
7	 *
8	 * Two streaming modes are supported transparently:
9	 *
10	 *   Default mode (no --include-partial-messages):
11	 *     `assistant` events carry complete content blocks. The parser emits
12	 *     stream.text / stream.thinking / stream.tool_use with final:true immediately.
13	 *
14	 *   Partial-messages mode (--include-partial-messages):
15	 *     `stream_event` SSE wrappers arrive before the complete `assistant` event.
16	 *     The parser emits incremental stream.text / stream.thinking deltas with
17	 *     final:false, then a final (empty-delta) event on content_block_stop.
18	 *     `assistant` events for text/thinking blocks are suppressed to avoid
19	 *     duplicates; tool_use events are still emitted from `assistant`.
20	 *
21	 * Empirical basis: docs/research/stream-json-semantics.md, captured
22	 * 2026-04-12 with Claude Code 2.1.104 / claude-opus-4-6.
23	 *
24	 * Usage:
25	 *   const parser = new StreamJsonParser();
26	 *   parser.on('stream.text', ev => { ... });
27	 *   handle.on('stdout_line', line => parser.feed(line));
28	 */
29	
30	import { EventEmitter } from 'node:events';
31	
32	// ---------------------------------------------------------------------------
33	// Event type definitions
34	// ---------------------------------------------------------------------------
35	
36	/** Incremental text delta from a text content block. */
37	export interface StreamTextEvent {
38	  type: 'stream.text';
39	  /** Content block index (from stream_event) or sequential counter (default mode). */
40	  blockId: number;
41	  /** The text delta for this event. Empty string on the final (content_block_stop) event. */
42	  textDelta: string;
43	  /**
44	   * true on the last event for a block:
45	   *   - Partial mode: fired when content_block_stop arrives.
46	   *   - Default mode: always true (single complete event per block).
47	   */
48	  final: boolean;
49	}
50	
51	/** Incremental thinking delta from a thinking content block. */
52	export interface StreamThinkingEvent {
53	  type: 'stream.thinking';
54	  blockId: number;
55	  thinkingDelta: string;
56	  final: boolean;
57	}
58	
59	/** Complete tool_use content block, emitted from the full `assistant` event. */
60	export interface StreamToolUseEvent {
61	  type: 'stream.tool_use';
62	  /** Anthropic tool_use ID (`toolu_...`). */
63	  toolUseId: string;
64	  name: string;
65	  input: unknown;
66	}
67	
68	/**
69	 * Tool result from a `user` event following a stream.tool_use.
70	 * AC: stream.tool_result always follows matching stream.tool_use within a session.
71	 */
72	export interface StreamToolResultEvent {
73	  type: 'stream.tool_result';
74	  /** Matches the toolUseId of the preceding stream.tool_use. */
75	  toolUseId: string;
76	  content: string;
77	  isError: boolean;
78	}
79	
80	/**
81	 * Session-cumulative token usage, emitted from the `result` event.
82	 * Carries all four token fields required by the acceptance criteria.
83	 */
84	export interface StreamUsageEvent {
85	  type: 'stream.usage';
86	  inputTokens: number;
87	  outputTokens: number;
88	  cacheCreationInputTokens: number;
89	  cacheReadInputTokens: number;
90	}
91	
92	/** Informational system event (init, hook_started, hook_response). */
93	export interface StreamSystemNoticeEvent {
94	  type: 'stream.system_notice';
95	  subtype: string;
96	  data: unknown;
97	}
98	
99	/**
100	 * Rate limit detected: `rate_limit_event.rate_limit_info.status !== "allowed"`.
101	 *
102	 * Empirical note: no actual `status="rejected"` frame was captured during
103	 * Phase γ research. The detection pattern matches the observed format from
104	 * docs/research/stream-json-semantics.md §3.6 with the status field inverted.
105	 */
106	export interface RateLimitDetectedEvent {
107	  type: 'rate_limit_detected';
108	  /** Unix timestamp (seconds) when the window resets, if present in the frame. */
109	  resetAt?: number;
110	}
111	
112	/**
113	 * Emitted when a stdout line cannot be parsed as JSON or is not a JSON object.
114	 * The consumer (Pipeline Engine) is responsible for incrementing
115	 * sessions.status_flags.parse_errors in SQLite — this event carries the
116	 * information needed to do so.
117	 */
118	export interface ParseErrorEvent {
119	  type: 'parse_error';
120	  line: string;
121	  error: string;
122	}
123	
124	export type StreamJsonEvent =
125	  | StreamTextEvent
126	  | StreamThinkingEvent
127	  | StreamToolUseEvent
128	  | StreamToolResultEvent
129	  | StreamUsageEvent
130	  | StreamSystemNoticeEvent
131	  | RateLimitDetectedEvent
132	  | ParseErrorEvent;
133	
134	// ---------------------------------------------------------------------------
135	// StreamJsonParser
136	// ---------------------------------------------------------------------------
137	
138	/**
139	 * NDJSON line-buffered stream-json parser.
140	 *
141	 * Feed data via `feedChunk(data)` (arbitrary byte chunks) or `feed(line)` (one
142	 * complete newline-stripped line). Use `flush()` when the stream ends to
143	 * process any remaining partial line.
144	 */
145	export class StreamJsonParser extends EventEmitter {
146	  /**
147	   * Partial-line accumulation buffer for feedChunk(). Splits on LF only —
148	   * no CRLF, no bare CR (matches research finding: delimiter is 0x0a only).
149	   */
150	  private _lineBuf = '';
151	
152	  /**
153	   * true once any `stream_event` line has been processed. Used to switch
154	   * between default-mode and partial-messages-mode `assistant` handling.
155	   */
156	  private _seenStreamEvent = false;
157	
158	  /**
159	   * Tracks content block types in partial-messages mode.
160	   * key = content block index; value = block type.
161	   */
162	  private _blockTypes = new Map<number, 'text' | 'thinking' | 'tool_use'>();
163	
164	  /**
165	   * Sequential block ID counter for default mode (no stream_event flow).
166	   * Incremented each time a text or thinking block is emitted from an
167	   * `assistant` event.
168	   */
169	  private _nextBlockId = 0;
170	
171	  // -------------------------------------------------------------------------
172	  // Public feed interface
173	  // -------------------------------------------------------------------------
174	
175	  /**
176	   * Feed a chunk of raw stdout data. Splits on LF (`\n`) and processes each
177	   * complete line independently. Partial lines are buffered until the next LF.
178	   * No assumption is made about chunk size — a chunk may contain zero, one, or
179	   * many complete lines.
180	   */
181	  feedChunk(data: string): void {
182	    this._lineBuf += data;
183	    const parts = this._lineBuf.split('\n');
184	    // The last element is either an incomplete line or empty (trailing \n).
185	    this._lineBuf = parts.pop() ?? '';
186	    for (const line of parts) {
187	      this.feed(line);
188	    }
189	  }
190	
191	  /**
192	   * Flush any remaining data in the line buffer. Call after the stream ends
193	   * to ensure the final partial line (if any) is processed.
194	   */
195	  flush(): void {
196	    if (this._lineBuf.trim()) {
197	      this.feed(this._lineBuf);
198	      this._lineBuf = '';
199	    }
200	  }
201	
202	  /**
203	   * Process a single complete stdout line (already split at LF).
204	   * Empty lines are silently skipped.
205	   * A malformed line emits `parse_error` and returns — processing continues.
206	   */
207	  feed(line: string): void {
208	    const trimmed = line.trim();
209	    if (!trimmed) return;
210	
211	    let obj: unknown;
212	    try {
213	      obj = JSON.parse(trimmed);
214	    } catch (err) {
215	      this._emitParseError(line, err instanceof Error ? err.message : String(err));
216	      return;
217	    }
218	
219	    if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
220	      this._emitParseError(line, 'Parsed value is not a JSON object');
221	      return;
222	    }
223	
224	    this._dispatch(obj as Record<string, unknown>);
225	  }
226	
227	  // -------------------------------------------------------------------------
228	  // Typed event overloads
229	  // -------------------------------------------------------------------------
230	
231	  on(event: 'stream.text', listener: (ev: StreamTextEvent) => void): this;
232	  on(event: 'stream.thinking', listener: (ev: StreamThinkingEvent) => void): this;
233	  on(event: 'stream.tool_use', listener: (ev: StreamToolUseEvent) => void): this;
234	  on(event: 'stream.tool_result', listener: (ev: StreamToolResultEvent) => void): this;
235	  on(event: 'stream.usage', listener: (ev: StreamUsageEvent) => void): this;
236	  on(event: 'stream.system_notice', listener: (ev: StreamSystemNoticeEvent) => void): this;
237	  on(event: 'rate_limit_detected', listener: (ev: RateLimitDetectedEvent) => void): this;
238	  on(event: 'parse_error', listener: (ev: ParseErrorEvent) => void): this;
239	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
240	  on(event: string | symbol, listener: (...args: any[]) => void): this {
241	    return super.on(event, listener);
242	  }
243	
244	  once(event: 'stream.text', listener: (ev: StreamTextEvent) => void): this;
245	  once(event: 'stream.thinking', listener: (ev: StreamThinkingEvent) => void): this;
246	  once(event: 'stream.tool_use', listener: (ev: StreamToolUseEvent) => void): this;
247	  once(event: 'stream.tool_result', listener: (ev: StreamToolResultEvent) => void): this;
248	  once(event: 'stream.usage', listener: (ev: StreamUsageEvent) => void): this;
249	  once(event: 'stream.system_notice', listener: (ev: StreamSystemNoticeEvent) => void): this;
250	  once(event: 'rate_limit_detected', listener: (ev: RateLimitDetectedEvent) => void): this;
251	  once(event: 'parse_error', listener: (ev: ParseErrorEvent) => void): this;
252	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
253	  once(event: string | symbol, listener: (...args: any[]) => void): this {
254	    return super.once(event, listener);
255	  }
256	
257	  // -------------------------------------------------------------------------
258	  // Dispatch
259	  // -------------------------------------------------------------------------
260	
261	  private _dispatch(obj: Record<string, unknown>): void {
262	    const type = obj['type'] as string | undefined;
263	    switch (type) {
264	      case 'system':
265	        this._handleSystem(obj);
266	        break;
267	      case 'assistant':
268	        this._handleAssistant(obj);
269	        break;
270	      case 'user':
271	        this._handleUser(obj);
272	        break;
273	      case 'stream_event':
274	        this._seenStreamEvent = true;
275	        this._handleStreamEvent(obj);
276	        break;
277	      case 'rate_limit_event':
278	        this._handleRateLimitEvent(obj);
279	        break;
280	      case 'result':
281	        this._handleResult(obj);
282	        break;
283	      // Unknown top-level types are silently ignored (forward compatibility).
284	    }
285	  }
286	
287	  // -------------------------------------------------------------------------
288	  // Event handlers
289	  // -------------------------------------------------------------------------
290	
291	  private _handleSystem(obj: Record<string, unknown>): void {
292	    const ev: StreamSystemNoticeEvent = {
293	      type: 'stream.system_notice',
294	      subtype: typeof obj['subtype'] === 'string' ? obj['subtype'] : '',
295	      data: obj,
296	    };
297	    this.emit('stream.system_notice', ev);
298	  }
299	
300	  private _handleAssistant(obj: Record<string, unknown>): void {
301	    const msg = obj['message'];
302	    if (msg === null || typeof msg !== 'object' || Array.isArray(msg)) return;
303	    const msgObj = msg as Record<string, unknown>;
304	
305	    const content = msgObj['content'];
306	    if (!Array.isArray(content)) return;
307	
308	    for (const block of content as unknown[]) {
309	      if (block === null || typeof block !== 'object' || Array.isArray(block)) continue;
310	      const b = block as Record<string, unknown>;
311	      const blockType = b['type'] as string | undefined;
312	
313	      if (blockType === 'text') {
314	        if (this._seenStreamEvent) {
315	          // Partial-messages mode: already emitted via stream_event deltas.
316	          // Suppress to avoid duplicate stream.text events.
317	          continue;
318	        }
319	        // Default mode: emit the complete text block as a single final event.
320	        const ev: StreamTextEvent = {
321	          type: 'stream.text',
322	          blockId: this._nextBlockId++,
323	          textDelta: typeof b['text'] === 'string' ? b['text'] : '',
324	          final: true,
325	        };
326	        this.emit('stream.text', ev);
327	      } else if (blockType === 'thinking') {
328	        if (this._seenStreamEvent) {
329	          continue; // Same suppression as text.
330	        }
331	        const ev: StreamThinkingEvent = {
332	          type: 'stream.thinking',
333	          blockId: this._nextBlockId++,
334	          thinkingDelta: typeof b['thinking'] === 'string' ? b['thinking'] : '',
335	          final: true,
336	        };
337	        this.emit('stream.thinking', ev);
338	      } else if (blockType === 'tool_use') {
339	        // tool_use is always emitted from the complete `assistant` event,
340	        // in both default and partial-messages mode. The input is fully
341	        // assembled here (streaming input_json_delta is not exposed).
342	        const ev: StreamToolUseEvent = {
343	          type: 'stream.tool_use',
344	          toolUseId: typeof b['id'] === 'string' ? b['id'] : '',
345	          name: typeof b['name'] === 'string' ? b['name'] : '',
346	          input: b['input'],
347	        };
348	        this.emit('stream.tool_use', ev);
349	      }
350	      // Other block types (e.g. image) are silently ignored.
351	    }
352	  }
353	
354	  private _handleUser(obj: Record<string, unknown>): void {
355	    const msg = obj['message'];
356	    if (msg === null || typeof msg !== 'object' || Array.isArray(msg)) return;
357	    const msgObj = msg as Record<string, unknown>;
358	
359	    const content = msgObj['content'];
360	    if (!Array.isArray(content)) return;
361	
362	    for (const block of content as unknown[]) {
363	      if (block === null || typeof block !== 'object' || Array.isArray(block)) continue;
364	      const b = block as Record<string, unknown>;
365	      if (b['type'] !== 'tool_result') continue;
366	
367	      const raw = b['content'];
368	      const contentStr =
369	        typeof raw === 'string' ? raw : raw !== null && raw !== undefined ? JSON.stringify(raw) : '';
370	      const ev: StreamToolResultEvent = {
371	        type: 'stream.tool_result',
372	        toolUseId: typeof b['tool_use_id'] === 'string' ? b['tool_use_id'] : '',
373	        content: contentStr,
374	        isError: b['is_error'] === true,
375	      };
376	      this.emit('stream.tool_result', ev);
377	    }
378	  }
379	
380	  private _handleStreamEvent(obj: Record<string, unknown>): void {
381	    const event = obj['event'];
382	    if (event === null || typeof event !== 'object' || Array.isArray(event)) return;
383	    const ev = event as Record<string, unknown>;
384	
385	    const evType = ev['type'] as string | undefined;
386	    const index = typeof ev['index'] === 'number' ? ev['index'] : undefined;
387	
388	    switch (evType) {
389	      case 'content_block_start': {
390	        if (index === undefined) break;
391	        const cb = ev['content_block'];
392	        if (cb === null || typeof cb !== 'object' || Array.isArray(cb)) break;
393	        const cbObj = cb as Record<string, unknown>;
394	        const cbType = cbObj['type'] as string | undefined;
395	        if (cbType === 'text' || cbType === 'thinking' || cbType === 'tool_use') {
396	          this._blockTypes.set(index, cbType);
397	        }
398	        break;
399	      }
400	
401	      case 'content_block_delta': {
402	        if (index === undefined) break;
403	        const delta = ev['delta'];
404	        if (delta === null || typeof delta !== 'object' || Array.isArray(delta)) break;
405	        const d = delta as Record<string, unknown>;
406	        const deltaType = d['type'] as string | undefined;
407	
408	        if (deltaType === 'text_delta') {
409	          const textEv: StreamTextEvent = {
410	            type: 'stream.text',
411	            blockId: index,
412	            textDelta: typeof d['text'] === 'string' ? d['text'] : '',
413	            final: false,
414	          };
415	          this.emit('stream.text', textEv);
416	        } else if (deltaType === 'thinking_delta') {
417	          const thinkEv: StreamThinkingEvent = {
418	            type: 'stream.thinking',
419	            blockId: index,
420	            thinkingDelta: typeof d['thinking'] === 'string' ? d['thinking'] : '',
421	            final: false,
422	          };
423	          this.emit('stream.thinking', thinkEv);
424	        }
425	        // input_json_delta: tool_use input streaming — not emitted here.
426	        // The complete tool_use is emitted from the assistant event instead.
427	        break;
428	      }
429	
430	      case 'content_block_stop': {
431	        if (index === undefined) break;
432	        const blockType = this._blockTypes.get(index);
433	        this._blockTypes.delete(index);
434	
435	        if (blockType === 'text') {
436	          // Emit final marker with empty delta.
437	          const finalEv: StreamTextEvent = {
438	            type: 'stream.text',
439	            blockId: index,
440	            textDelta: '',
441	            final: true,
442	          };
443	          this.emit('stream.text', finalEv);
444	        } else if (blockType === 'thinking') {
445	          const finalEv: StreamThinkingEvent = {
446	            type: 'stream.thinking',
447	            blockId: index,
448	            thinkingDelta: '',
449	            final: true,
450	          };
451	          this.emit('stream.thinking', finalEv);
452	        }
453	        // tool_use stop: no event — the tool_use was already emitted from assistant.
454	        break;
455	      }
456	
457	      // message_start, message_delta, message_stop: informational — not exposed.
458	    }
459	  }
460	
461	  private _handleRateLimitEvent(obj: Record<string, unknown>): void {
462	    const info = obj['rate_limit_info'];
463	    if (info === null || typeof info !== 'object' || Array.isArray(info)) return;
464	    const infoObj = info as Record<string, unknown>;
465	
466	    // status="allowed" is the normal case (observed in all Phase γ captures).
467	    // Any other status (expected: "rejected") indicates active rate limiting.
468	    if (infoObj['status'] === 'allowed') return;
469	
470	    const ev: RateLimitDetectedEvent = {
471	      type: 'rate_limit_detected',
472	    };
473	    // resetsAt is a Unix timestamp (seconds) when present.
474	    if (typeof infoObj['resetsAt'] === 'number') {
475	      ev.resetAt = infoObj['resetsAt'] as number;
476	    }
477	    this.emit('rate_limit_detected', ev);
478	  }
479	
480	  private _handleResult(obj: Record<string, unknown>): void {
481	    const usage = obj['usage'];
482	    if (usage === null || typeof usage !== 'object' || Array.isArray(usage)) return;
483	    const u = usage as Record<string, unknown>;
484	
485	    const ev: StreamUsageEvent = {
486	      type: 'stream.usage',
487	      inputTokens: typeof u['input_tokens'] === 'number' ? u['input_tokens'] : 0,
488	      outputTokens: typeof u['output_tokens'] === 'number' ? u['output_tokens'] : 0,
489	      cacheCreationInputTokens:
490	        typeof u['cache_creation_input_tokens'] === 'number'
491	          ? u['cache_creation_input_tokens']
492	          : 0,
493	      cacheReadInputTokens:
494	        typeof u['cache_read_input_tokens'] === 'number' ? u['cache_read_input_tokens'] : 0,
495	    };
496	    this.emit('stream.usage', ev);
497	  }
498	
499	  // -------------------------------------------------------------------------
500	  // Helpers
501	  // -------------------------------------------------------------------------
502	
503	  private _emitParseError(line: string, error: string): void {
504	    const ev: ParseErrorEvent = { type: 'parse_error', line, error };
505	    this.emit('parse_error', ev);
506	  }
507	}
508

