47	/** Register listeners for all typed events and collect them into an array. */
48	function collectAllEvents(parser: StreamJsonParser, events: StreamJsonEvent[]): void {
49	  const push = (ev: StreamJsonEvent): void => { events.push(ev); };
50	  parser.on('stream.text', push);
51	  parser.on('stream.thinking', push);
52	  parser.on('stream.tool_use', push);
53	  parser.on('stream.tool_result', push);
