60	/** Feed a fixture file line-by-line via feed() and collect all emitted events. */
61	function parseFixture(filename: string): StreamJsonEvent[] {
62	  const parser = new StreamJsonParser();
63	  const events: StreamJsonEvent[] = [];
64	  collectAllEvents(parser, events);
65	  const content = readFileSync(join(FIXTURES, filename), 'utf8');
66	  for (const line of content.split('\n')) {
