72	/** Feed a fixture file as fixed-size chunks via feedChunk() + flush(). */
73	function parseFixtureChunked(filename: string, chunkSize: number): StreamJsonEvent[] {
74	  const parser = new StreamJsonParser();
75	  const events: StreamJsonEvent[] = [];
76	  collectAllEvents(parser, events);
77	  const content = readFileSync(join(FIXTURES, filename), 'utf8');
