    const events = parseLines(overloaded);
    const rl = events.filter((e): e is RateLimitDetectedEvent => e.type === 'rate_limit_detected');
    expect(rl.length).toBe(1);
    expect(rl[0].resetAt).toBe(9999);
  });
});

